const config = {
  "previewFeatures": [],
  "clientVersion": "7.4.1",
  "engineVersion": "55ae170b1ced7fc6ed07a15f110549408c501bb3",
  "activeProvider": "postgresql",
  "inlineSchema": "// MiTurnoRD — Prisma Schema (Advanced Architecture)\n// SaaS multi-tenant platform for appointment management\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../src/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ─────────────────────────────────────────────\n// USER & AUTH\n// ─────────────────────────────────────────────\n\nmodel User {\n  id            String     @id @default(uuid())\n  full_name     String\n  email         String?    @unique\n  phone         String?    @unique\n  document_id   String?\n  password_hash String\n  status        UserStatus @default(active)\n  created_at    DateTime   @default(now())\n  updated_at    DateTime   @updatedAt\n\n  roles                   UserRole[]\n  sessions                AuthSession[]\n  institution_memberships InstitutionUser[]\n  appointments            Appointment[]\n}\n\nmodel Role {\n  id   Int    @id @default(autoincrement())\n  name String @unique\n\n  users UserRole[]\n}\n\nmodel UserRole {\n  user_id String\n  role_id Int\n\n  user User @relation(fields: [user_id], references: [id])\n  role Role @relation(fields: [role_id], references: [id])\n\n  @@id([user_id, role_id])\n}\n\nmodel AuthSession {\n  id         String   @id @default(uuid())\n  user_id    String\n  token      String\n  expires_at DateTime\n  created_at DateTime @default(now())\n\n  user User @relation(fields: [user_id], references: [id])\n}\n\nenum UserStatus {\n  active\n  blocked\n  deleted\n}\n\n// ─────────────────────────────────────────────\n// SAAS ADMIN\n// ─────────────────────────────────────────────\n\nmodel SaasAdmin {\n  id            String   @id @default(uuid())\n  email         String   @unique\n  full_name     String?\n  password_hash String\n  created_at    DateTime @default(now())\n  updated_at    DateTime @updatedAt\n}\n\n// ─────────────────────────────────────────────\n// INSTITUTION TYPES & DYNAMIC FIELDS\n// ─────────────────────────────────────────────\n\nmodel InstitutionType {\n  id          String   @id @default(uuid())\n  name        String   @unique\n  description String?\n  icon        String? // emoji or icon key for UI\n  created_at  DateTime @default(now())\n\n  institutions Institution[]\n}\n\nmodel CustomField {\n  id          String    @id @default(uuid())\n  label       String\n  placeholder String?\n  field_type  FieldType\n  required    Boolean   @default(false)\n  options     String? // JSON string for SELECT type options\n  order       Int       @default(0)\n\n  // Relations: Field belongs to an Institution.\n  // Optionally, it applies only to a specific Service.\n  institution_id String\n  service_id     String?\n\n  institution Institution                @relation(fields: [institution_id], references: [id], onDelete: Cascade)\n  service     Service?                   @relation(fields: [service_id], references: [id], onDelete: Cascade)\n  responses   AppointmentFieldResponse[]\n}\n\nenum FieldType {\n  TEXT\n  NUMBER\n  DATE\n  SELECT\n  EMAIL\n  PHONE\n  FILE\n}\n\n// ─────────────────────────────────────────────\n// INSTITUTION\n// ─────────────────────────────────────────────\n\nmodel Institution {\n  id                  String            @id @default(uuid())\n  name                String\n  slug                String            @unique\n  description         String?\n  logo_url            String? // URL imagen/logo de la institución\n  address             String?\n  phone               String?\n  email               String?\n  institution_type_id String\n  status              InstitutionStatus @default(active)\n  is_public           Boolean           @default(false) // true = visible en marketplace público\n  created_at          DateTime          @default(now())\n  updated_at          DateTime          @updatedAt\n\n  institution_type InstitutionType   @relation(fields: [institution_type_id], references: [id])\n  users            InstitutionUser[]\n  services         Service[]\n  schedules        Schedule[]\n  appointments     Appointment[]\n  branches         Branch[]\n  business_rule    BusinessRule?\n  custom_fields    CustomField[]\n}\n\nenum InstitutionStatus {\n  active\n  inactive\n  suspended\n}\n\nmodel InstitutionUser {\n  id             String          @id @default(uuid())\n  institution_id String\n  user_id        String\n  role           InstitutionRole\n  created_at     DateTime        @default(now())\n\n  institution Institution @relation(fields: [institution_id], references: [id])\n  user        User        @relation(fields: [user_id], references: [id])\n\n  @@unique([institution_id, user_id])\n}\n\nenum InstitutionRole {\n  OWNER\n  STAFF\n  MANAGER\n}\n\n// ─────────────────────────────────────────────\n// BRANCHES (Sucursales)\n// ─────────────────────────────────────────────\n\nmodel Branch {\n  id             String   @id @default(uuid())\n  institution_id String\n  name           String\n  address        String?\n  city           String?\n  phone          String?\n  latitude       Float?\n  longitude      Float?\n  is_main        Boolean  @default(false)\n  active         Boolean  @default(true)\n  created_at     DateTime @default(now())\n  updated_at     DateTime @updatedAt\n\n  institution   Institution     @relation(fields: [institution_id], references: [id])\n  schedules     Schedule[]\n  appointments  Appointment[]\n  blocked_times BlockedTime[]\n  services      BranchService[]\n}\n\n// ─────────────────────────────────────────────\n// BRANCH ↔ SERVICE (M:N — not all services exist in all branches)\n// ─────────────────────────────────────────────\n\nmodel BranchService {\n  branch_id  String\n  service_id String\n  active     Boolean  @default(true)\n  created_at DateTime @default(now())\n\n  branch  Branch  @relation(fields: [branch_id], references: [id], onDelete: Cascade)\n  service Service @relation(fields: [service_id], references: [id], onDelete: Cascade)\n\n  @@id([branch_id, service_id])\n}\n\n// ─────────────────────────────────────────────\n// SERVICES\n// ─────────────────────────────────────────────\n\nmodel Service {\n  id             String   @id @default(uuid())\n  name           String\n  description    String?\n  image_url      String? // URL imagen del servicio\n  duration       Int // minutes\n  price          Decimal? @db.Decimal(10, 2)\n  institution_id String\n  active         Boolean  @default(true)\n  created_at     DateTime @default(now())\n  updated_at     DateTime @updatedAt\n\n  institution   Institution     @relation(fields: [institution_id], references: [id])\n  appointments  Appointment[]\n  custom_fields CustomField[]\n  branches      BranchService[]\n}\n\n// ─────────────────────────────────────────────\n// SCHEDULES (Weekly availability)\n// ─────────────────────────────────────────────\n\nmodel Schedule {\n  id             String   @id @default(uuid())\n  day_of_week    Int // 0=Sunday, 1=Monday, ... 6=Saturday\n  start_time     String // \"08:00\"\n  end_time       String // \"17:00\"\n  institution_id String\n  branch_id      String?\n  active         Boolean  @default(true)\n  created_at     DateTime @default(now())\n\n  institution Institution @relation(fields: [institution_id], references: [id])\n  branch      Branch?     @relation(fields: [branch_id], references: [id])\n\n  @@unique([institution_id, branch_id, day_of_week])\n}\n\n// ─────────────────────────────────────────────\n// BLOCKED TIMES (Manual slot blocks)\n// ─────────────────────────────────────────────\n\nmodel BlockedTime {\n  id         String   @id @default(uuid())\n  branch_id  String\n  date       DateTime @db.Date\n  start_time String // \"HH:MM\"\n  end_time   String // \"HH:MM\"\n  reason     String?\n  created_at DateTime @default(now())\n\n  branch Branch @relation(fields: [branch_id], references: [id])\n}\n\n// ─────────────────────────────────────────────\n// BUSINESS RULES (Automation config)\n// ─────────────────────────────────────────────\n\nmodel BusinessRule {\n  id                   String   @id @default(uuid())\n  institution_id       String   @unique\n  auto_confirm         Boolean  @default(true)\n  buffer_minutes       Int      @default(0)\n  max_per_slot         Int      @default(1)\n  no_show_minutes      Int      @default(30)\n  advance_book_days    Int      @default(30)\n  reminder_days_before Int      @default(1)\n  created_at           DateTime @default(now())\n  updated_at           DateTime @updatedAt\n\n  institution Institution @relation(fields: [institution_id], references: [id])\n}\n\n// ─────────────────────────────────────────────\n// SYSTEM SETTINGS (SAAS Admin Config)\n// ─────────────────────────────────────────────\n\nmodel SystemSetting {\n  id                              String   @id @default(\"singleton\")\n  cron_reminder_frequency_minutes Int      @default(60)\n  log_retention_days              Int      @default(7)\n  updated_at                      DateTime @updatedAt\n}\n\n// ─────────────────────────────────────────────\n// REMINDER LOGS\n// ─────────────────────────────────────────────\n\nmodel ReminderLog {\n  id             String   @id @default(uuid())\n  appointment_id String\n  user_email     String\n  status         String // e.g. \"SUCCESS\", \"FAILED\"\n  error_details  String?\n  created_at     DateTime @default(now())\n}\n\n// ─────────────────────────────────────────────\n// APPOINTMENTS\n// ─────────────────────────────────────────────\n\nmodel Appointment {\n  id                  String            @id @default(uuid())\n  date                DateTime\n  status              AppointmentStatus @default(PENDING)\n  notes               String?\n  institution_id      String\n  service_id          String\n  user_id             String? // null para walk-ins sin cuenta en la plataforma\n  branch_id           String?\n  rescheduled_from_id String?\n  reminder_sent       Boolean           @default(false)\n  // Campos de reserva interna (front-desk)\n  booked_by_staff     Boolean           @default(false)\n  walk_in_name        String?\n  walk_in_phone       String?\n  walk_in_email       String?\n  created_at          DateTime          @default(now())\n  updated_at          DateTime          @updatedAt\n\n  institution Institution                @relation(fields: [institution_id], references: [id])\n  service     Service                    @relation(fields: [service_id], references: [id])\n  user        User?                      @relation(fields: [user_id], references: [id])\n  branch      Branch?                    @relation(fields: [branch_id], references: [id])\n  responses   AppointmentFieldResponse[]\n}\n\nenum AppointmentStatus {\n  PENDING\n  CONFIRMED\n  RESCHEDULED\n  CANCELLED\n  COMPLETED\n  NO_SHOW\n}\n\n// Dynamic field responses for each appointment\nmodel AppointmentFieldResponse {\n  id             String @id @default(uuid())\n  appointment_id String\n  field_id       String\n  value          String\n\n  appointment Appointment @relation(fields: [appointment_id], references: [id], onDelete: Cascade)\n  field       CustomField @relation(fields: [field_id], references: [id])\n\n  @@unique([appointment_id, field_id])\n}\n"
}

